@namespace Lumeo
@inject IComponentInteropService Interop

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium text-foreground mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<input id="@EffectiveId"
       class="@CssClass"
       value="@_displayValue"
       placeholder="@EffectivePlaceholder"
       disabled="@Disabled"
       name="@(Name ?? FormField?.Name)"
       aria-required="@(Required ? "true" : "false")"
       aria-invalid="@(EffectiveInvalid ? "true" : "false")"
       aria-describedby="@FormFieldDescribedBy"
       @oninput="HandleInput"
       @attributes="EffectiveAttributes" />

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive mt-1.5">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground mt-1.5">@HelperText</p>
    }
}
</div>

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    /// <summary>The unmasked (raw) value — only the mask-significant characters, without literals. Pair with <see cref="ValueChanged"/> for two-way binding.</summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Raised after each edit with the updated raw value.</summary>
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }

    /// <summary>The mask pattern: <c>#</c> matches a digit, <c>A</c> a letter, <c>*</c> any character; any other character is a literal inserted verbatim (e.g. <c>"(###) ###-####"</c>).</summary>
    [Parameter] public string Mask { get; set; } = "";

    /// <summary>Placeholder shown when empty. When unset, derived from <see cref="Mask"/> with each significant slot replaced by <see cref="PromptChar"/>.</summary>
    [Parameter] public string? Placeholder { get; set; }

    /// <summary>Character used to fill unfilled mask slots when building the default placeholder. Defaults to <c>'_'</c>.</summary>
    [Parameter] public char PromptChar { get; set; } = '_';

    /// <summary>Disables interaction and dims the input.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>Marks the field as required: sets <c>aria-required</c> and renders a destructive-colored asterisk after <see cref="Label"/>.</summary>
    [Parameter] public bool Required { get; set; }

    /// <summary>Forces the invalid/error visual and <c>aria-invalid</c>, independent of any cascaded <see cref="FormField"/> error state.</summary>
    [Parameter] public bool Invalid { get; set; }

    /// <summary>Error message shown below the input when invalid and not composed inside a <see cref="FormField"/> (which owns its own error display).</summary>
    [Parameter] public string? ErrorText { get; set; }

    /// <summary>Helper text shown below the input when not invalid and not composed inside a <see cref="FormField"/>.</summary>
    [Parameter] public string? HelperText { get; set; }

    /// <summary>Visible label rendered above the input when not composed inside a <see cref="FormField"/> (which renders its own label).</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>Field name for the native <c>&lt;input&gt;</c>. Falls back to the cascaded <see cref="FormField"/>'s name when unset.</summary>
    [Parameter] public string? Name { get; set; }

    /// <summary>Additional CSS classes merged onto the input element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the input element (an explicit <c>id</c> is ignored when inside a <see cref="FormField"/>).</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Point aria-describedby at the FormField's rendered help/error text so a screen
    // reader announces it on this input (null outside a FormField).
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // A consumer-supplied id in the splat would otherwise render AFTER the generated
    // EffectiveId attribute and silently win, leaving the FormField label's `for`
    // pointing at an id that no longer exists on the input. Strip it from the splat
    // when inside a FormField; outside a FormField the splat passes through unchanged
    // so the consumer's id still reaches the input.
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    // Inside a FormField, adopt its ControlId as the input's id so the field's
    // <Label For> actually click-focuses it (Base UI Field parity, matching
    // Select/Textarea/DatePicker/TimePicker). Standalone, keep our own generated id.
    // Every internal id use (the rendered id attribute and the caret JS interop in
    // HandleInput/OnAfterRenderAsync) flows through this so the rendered id and the
    // focus/caret targets stay consistent.
    private string EffectiveId =>
        !string.IsNullOrEmpty(FormField?.ControlId) ? FormField!.ControlId : _id;

    private readonly string _id = LumeoIds.New("inputmask");

    private string _displayValue = "";
    private string _rawValue = "";
    // Set in HandleInput to ask OnAfterRender to restore the caret to this display
    // index. -1 means "no pending restore".
    private int _pendingCaret = -1;
    // Set in HandleInput when the re-masked display differs from the raw browser
    // string (a char was rejected or a literal auto-inserted). OnAfterRender then
    // force-writes _displayValue to the DOM because Blazor's diff may not patch an
    // input whose value attribute equals the PREVIOUS render's value (#41).
    private bool _pendingValueSync;
    // Last Mask / PromptChar the display was derived against, so OnParametersSet
    // re-derives the masked display when the mask definition changes even though
    // the bound Value stayed the same (#155).
    private string _lastMask = "";
    private char _lastPromptChar = '_';

    // UNCONTROLLED discriminator: the last Value parameter we observed. When the
    // consumer does NOT bind ValueChanged the component owns the live value, so we
    // adopt the parameter only when it genuinely CHANGES from this — an unrelated
    // re-render that re-supplies the same/stale Value must not clobber typed text.
    private string? _lastValueParam;
    // CONTROLLED discriminator: the last value we pushed UP to the parent via
    // ValueChanged (also re-synced whenever we adopt an authoritative Value). A
    // controlled parent re-render that echoes back this exact value is safe to
    // ignore (keep in-flight state); any other value — a normalization, reset, or
    // a REJECTION that kept the OLD value — is authoritative and must win.
    private string? _lastPushed;
    private bool _paramSeeded;

    private string CssClass => Cx.Merge("flex h-9 w-full rounded-md border", (EffectiveInvalid ? "border-destructive focus-visible:ring-destructive/20" : "border-input focus-visible:ring-ring"), "bg-transparent px-3 py-1 text-sm transition-colors placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] disabled:cursor-not-allowed disabled:opacity-50", Class);

    private string EffectivePlaceholder => Placeholder ?? BuildMaskPlaceholder();

    protected override void OnParametersSet()
    {
        // Seed the working value from the parameter on the first set. _lastPushed and
        // _lastValueParam both start at the seed so neither discriminator misfires.
        if (!_paramSeeded)
        {
            _rawValue = Value ?? "";
            _displayValue = ApplyMask(_rawValue);
            _lastValueParam = Value;
            _lastPushed = Value;
            _lastMask = Mask;
            _lastPromptChar = PromptChar;
            _paramSeeded = true;
            return;
        }

        // The two usages need opposite defaults, distinguished by whether the consumer
        // bound ValueChanged (the established controlled/uncontrolled signal used across
        // the library). HandleInput mutates _rawValue (not Value) and records _lastPushed,
        // so in BOTH branches our own in-flight typing is never clobbered.
        bool adoptValue;
        if (ValueChanged.HasDelegate)
        {
            // CONTROLLED: the parent owns Value and it is authoritative — EXCEPT when it
            // merely echoes back the exact edit we just pushed (Value == _lastPushed),
            // where adopting would be a redundant write that could disturb the caret, so
            // we keep the live value. Any OTHER Value wins and is adopted: a normalization,
            // a programmatic (re)assignment, or — crucially — a REJECTION where the parent
            // kept its OLD value (!= the value we just pushed). That last case is what
            // rolls a rejected keystroke back to the controlled Value.
            adoptValue = !string.Equals(Value, _lastPushed, StringComparison.Ordinal);
        }
        else
        {
            // UNCONTROLLED: no ValueChanged binding, so the component owns the live value.
            // Adopt the parameter ONLY when the PARENT actually changes it; an unrelated
            // re-render that re-supplies the same (or a stale) Value must NOT clobber the
            // user's typed text.
            adoptValue = !string.Equals(Value, _lastValueParam, StringComparison.Ordinal);
        }

        // Re-derive the masked display when adopting Value OR when the mask
        // definition itself changes (Mask / PromptChar) while Value stays the
        // same — otherwise a runtime mask swap left a stale display (#155).
        if (adoptValue || Mask != _lastMask || PromptChar != _lastPromptChar)
        {
            if (adoptValue)
            {
                _rawValue = Value ?? "";
                _lastPushed = Value;
            }
            _displayValue = ApplyMask(_rawValue);
            _lastMask = Mask;
            _lastPromptChar = PromptChar;
        }

        // Keep the uncontrolled discriminator pointing at the last Value we observed.
        _lastValueParam = Value;
    }

    private string BuildMaskPlaceholder()
    {
        if (string.IsNullOrEmpty(Mask)) return "";
        return new string(Mask.Select(c => IsMaskChar(c) ? PromptChar : c).ToArray());
    }

    private bool IsMaskChar(char c) => c == '#' || c == 'A' || c == '*';

    private bool MatchesMaskChar(char maskChar, char inputChar) => maskChar switch
    {
        '#' => char.IsDigit(inputChar),
        'A' => char.IsLetter(inputChar),
        '*' => true,
        _ => false
    };

    private string ApplyMask(string raw)
    {
        if (string.IsNullOrEmpty(Mask)) return raw;

        var result = new System.Text.StringBuilder();
        int rawIndex = 0;

        foreach (char maskChar in Mask)
        {
            if (rawIndex >= raw.Length) break;

            if (IsMaskChar(maskChar))
            {
                // Find next matching raw character
                while (rawIndex < raw.Length && !MatchesMaskChar(maskChar, raw[rawIndex]))
                    rawIndex++;

                if (rawIndex < raw.Length)
                {
                    result.Append(raw[rawIndex]);
                    rawIndex++;
                }
                else
                {
                    break;
                }
            }
            else
            {
                result.Append(maskChar);
            }
        }

        return result.ToString();
    }

    private string ExtractRaw(string display)
    {
        if (string.IsNullOrEmpty(Mask)) return display;

        var raw = new System.Text.StringBuilder();
        int maskIndex = 0;

        for (int i = 0; i < display.Length && maskIndex < Mask.Length; i++)
        {
            // Advance mask past literal chars
            while (maskIndex < Mask.Length && !IsMaskChar(Mask[maskIndex]))
                maskIndex++;

            if (maskIndex >= Mask.Length) break;

            if (MatchesMaskChar(Mask[maskIndex], display[i]))
            {
                raw.Append(display[i]);
                maskIndex++;
            }
        }

        return raw.ToString();
    }

    // Single source of truth for value changes — both typing AND deletion arrive
    // here as native input events, so ValueChanged fires exactly once per edit.
    // The previous component also handled Backspace in @onkeydown and fired
    // ValueChanged a SECOND time, and that branch always dropped the LAST raw char
    // (_rawValue[..^1]) regardless of the caret. Deleting via the native input
    // event is inherently caret-correct: the browser removes the char under the
    // caret and we re-derive the raw value from the resulting display (#177).
    private async Task HandleInput(ChangeEventArgs e)
    {
        var inputVal = e.Value?.ToString() ?? "";

        // Read the caret BEFORE we rewrite the value — the DOM still holds the
        // post-edit string the browser produced, so selectionStart is meaningful.
        int browserCaret;
        try { browserCaret = await Interop.GetInputCaret(EffectiveId); }
        catch (JSDisconnectedException) { browserCaret = inputVal.Length; }

        _rawValue = ExtractRaw(inputVal);
        _displayValue = ApplyMask(_rawValue);
        // Record _lastPushed BEFORE raising ValueChanged: a controlled parent
        // re-renders synchronously inside InvokeAsync, so OnParametersSet must
        // already see this as "the value we pushed" to recognise the echo and
        // keep the caret (and, on a rejection, roll back to the parent's
        // authoritative value).
        _lastPushed = _rawValue;
        await ValueChanged.InvokeAsync(_rawValue);

        // When the masked display differs from what the browser produced (a char
        // was rejected, or a literal/separator was auto-inserted), the new
        // _displayValue may equal the PREVIOUS render's value — so Blazor's diff
        // emits no patch and the browser keeps showing the unmasked string. Ask
        // OnAfterRender to force-write the value to the DOM (#41).
        _pendingValueSync = _displayValue != inputVal;

        // Map the browser caret (in the typed string) onto the re-masked display:
        // count the significant chars before the caret, then land just after that
        // many filled slots (skipping any literals in between) so the next
        // keystroke fills the next slot rather than snapping to the end (#177).
        var rawBeforeCaret = CountRawBefore(inputVal, browserCaret);
        _pendingCaret = DisplayCaretForRawCount(rawBeforeCaret);
    }

    // How many mask-significant characters sit at or before the caret in the raw
    // (browser) string. Walks the mask in lockstep with the input so literal
    // characters the user typed over don't inflate the count.
    private int CountRawBefore(string inputVal, int caret)
    {
        if (string.IsNullOrEmpty(Mask)) return Math.Min(caret, inputVal.Length);

        var count = 0;
        var maskIndex = 0;
        var limit = Math.Min(caret, inputVal.Length);
        for (var i = 0; i < limit && maskIndex < Mask.Length; i++)
        {
            while (maskIndex < Mask.Length && !IsMaskChar(Mask[maskIndex]))
                maskIndex++;
            if (maskIndex >= Mask.Length) break;
            if (MatchesMaskChar(Mask[maskIndex], inputVal[i]))
            {
                count++;
                maskIndex++;
            }
        }
        return count;
    }

    // Display index positioned right after the Nth filled significant slot, with
    // any immediately-following literals consumed so the caret rests at the next
    // typeable slot (mirrors how InputMask libraries advance past separators).
    private int DisplayCaretForRawCount(int rawCount)
    {
        if (string.IsNullOrEmpty(Mask)) return Math.Min(rawCount, _displayValue.Length);

        var filled = 0;
        var i = 0;
        for (; i < _displayValue.Length && i < Mask.Length; i++)
        {
            if (filled >= rawCount) break;
            if (IsMaskChar(Mask[i])) filled++;
        }
        // Skip trailing literal chars so the next input lands on a significant slot.
        while (i < _displayValue.Length && i < Mask.Length && !IsMaskChar(Mask[i]))
            i++;
        return i;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Force the masked display into the DOM first (so the caret restore below
        // operates on the corrected string). This runs only when HandleInput saw
        // the display diverge from the raw browser string, i.e. a char was
        // rejected or a literal auto-inserted and Blazor's diff may not patch it
        // because the value equals the previous render (#41).
        if (_pendingValueSync)
        {
            _pendingValueSync = false;
            try { await Interop.SetInputValue(EffectiveId, _displayValue); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }

        if (_pendingCaret < 0) return;
        var pos = _pendingCaret;
        _pendingCaret = -1;
        try { await Interop.SetInputCaret(EffectiveId, pos); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }
}
